import re

def check_char(s):
    if not s:
        return 'Invalid'
    if re.match(r'^[a-zA-Z0-9][a-zA-Z0-9]*[a-zA-Z0-9]$', s):
        if s[0] == s[-1]:
            return 'Valid'
        else:
            return 'Invalid'
    else:
        return 'Invalid'

